1	//! Zero-copy no_std SPSC ring buffer over a caller-provided
2	//! memory region, per [notes/ring-buffer-design.md]:
3	//!
4	//! - One `#[repr(C)]` [`Header`] spanning four cache lines
5	//!   (immutable geometry, producer index, consumer index, app
6	//!   user words), followed by M slots of N bytes.
7	//! - Indices are free-running `AtomicU32`s, masked only at slot
8	//!   access; full is `p - c == M`, no sacrificial slot.
9	//! - Messages move in place: the producer writes through a
10	//!   [`WriteSlot`] `&mut T`, the consumer reads through a
11	//!   [`ReadSlot`] `&T` — zerocopy traits bound `T`, no
12	//!   serialization step. Each side reserves at most one slot at
13	//!   a time; the guard holds the endpoint borrow until commit /
14	//!   release (or drop).
15	//!
16	//! [notes/ring-buffer-design.md]: https://github.com/winksaville/zc-ring-x1/blob/main/notes/ring-buffer-design.md
17	
18	#![cfg_attr(not(test), no_std)]
19	
20	use core::marker::PhantomData;
21	use core::mem::{align_of, size_of};
22	use core::sync::atomic::{AtomicU32, Ordering};
23	
24	mod consumer;
25	pub mod policy;
26	mod pool;
27	mod producer;
28	mod registry;
29	
30	pub use consumer::{Consumer, Empty, ReadSlot};
31	pub use pool::{BufSlot, Exhausted, Pool, PoolHeader, PoolResolver};
32	pub use producer::{Full, Producer, WriteSlot};
33	pub use registry::{Desc, PoolId, PoolRegistry, RegistryError};
34	
35	/// Cache-line size the layout is built around.
36	///
37	/// - Slot size must be a multiple of this; slots and the region
38	///   itself must be aligned to it.
39	pub const CACHE_LINE_SIZE: usize = 64;
40	
41	/// Layout marker written by [`Ring::init`]; rejects foreign
42	/// regions on attach.
43	const MAGIC: u32 = 0x5A43_5231; // "ZCR1"
44	
45	/// Bumped on any change to the region layout.
46	const LAYOUT_VERSION: u32 = 2;
47	
48	/// Number of `AtomicU32` words in the header's app-owned
49	/// `user` line.
50	pub const USER_WORDS: usize = 16;
51	
52	/// Cache-line-aligned wrapper granting its field sole
53	/// ownership of the line.
54	///
55	/// - `repr(align(N))` accepts only an integer literal — it
56	///   cannot name [`CACHE_LINE_SIZE`] — so the `64` is written out
57	///   and a const assert ties them back together.
58	#[repr(C, align(64))]
59	struct CacheAligned<T>(T);
60	
61	const _: () = assert!(align_of::<CacheAligned<AtomicU32>>() == CACHE_LINE_SIZE);
62	
63	impl<T> core::ops::Deref for CacheAligned<T> {
64	    type Target = T;
65	    /// Access the wrapped value.
66	    fn deref(&self) -> &T {
67	        &self.0
68	    }
69	}
70	
71	/// Control block at offset 0 of the region — one struct spanning
72	/// four cache lines so each concurrently-written index owns its
73	/// own line.
74	///
75	/// - line 0: geometry, written by [`Ring::init`] with `magic`
76	///   last (`Release`), read-only thereafter. Cold: per-op
77	///   paths use the handles' snapshots.
78	/// - line 1: `producer_idx`, written only by the producer.
79	/// - line 2: `consumer_idx`, written only by the consumer.
80	/// - line 3: `user`, app-owned scratch — last, so an app
81	///   overrun walks into its own slot data, not an index line.
82	/// - Every field is atomic: the region may be mapped by a peer
83	///   at any time, so even "immutable" fields must be free of
84	///   data races. `AtomicU32` has the same layout as `u32`, so
85	///   this does not affect `layout_version`.
86	#[repr(C)]
87	pub struct Header {
88	    /// Layout marker ([`MAGIC`]); stored last by init
89	    /// (`Release`), loaded first by attach (`Acquire`), so a
90	    /// peer that observes it also observes the geometry.
91	    magic: AtomicU32,
92	    /// Layout version ([`LAYOUT_VERSION`]).
93	    layout_version: AtomicU32,
94	    /// Slot size N in bytes — a [`CACHE_LINE_SIZE`] multiple.
95	    slot_size: AtomicU32,
96	    /// Slot count M — a power of two `<= 2^31`.
97	    capacity: AtomicU32,
98	    /// [`CACHE_LINE_SIZE`] this region was built with. The line size
99	    /// is a layout parameter (padding, offsets, slot granule),
100	    /// so builds must agree; attach validates it like the rest
101	    /// of the geometry.
102	    cache_line_size: AtomicU32,
103	    /// Free-running count of messages committed.
104	    producer_idx: CacheAligned<AtomicU32>,
105	    /// Free-running count of messages released.
106	    consumer_idx: CacheAligned<AtomicU32>,
107	    /// App-owned scratch line ([`USER_WORDS`] words): zeroed by
108	    /// init, then never read, written, or interpreted by the
109	    /// crate. See the design doc's "Blocking and user words".
110	    user: CacheAligned<[AtomicU32; USER_WORDS]>,
111	}
112	
113	const _: () = assert!(size_of::<Header>() == 4 * CACHE_LINE_SIZE);
114	
115	/// Errors from region validation — [`Ring::init`] /
116	/// [`Ring::attach`] and [`Pool::init`] / [`Pool::attach`].
117	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
118	pub enum Error {
119	    /// Region is not [`CACHE_LINE_SIZE`]-aligned.
120	    Misaligned,
121	    /// Region is smaller than header + slots/buffers.
122	    TooSmall,
123	    /// Slot size is zero or not a [`CACHE_LINE_SIZE`] multiple.
124	    BadSlotSize,
125	    /// Capacity is zero, not a power of two, or `> 2^31`.
126	    BadCapacity,
127	    /// Pool: buffer size is zero or not a [`CACHE_LINE_SIZE`]
128	    /// multiple.
129	    BadBufSize,
130	    /// Pool: buffer count is zero or `u32::MAX` (the
131	    /// free-stack NIL sentinel).
132	    BadBufCount,
133	    /// Attach: magic mismatch — not a region of the expected
134	    /// kind.
135	    BadMagic,
136	    /// Attach: layout version mismatch.
137	    BadLayoutVersion,
138	    /// Attach: region built with a different [`CACHE_LINE_SIZE`].
139	    BadCacheLine,
140	}
141	
142	/// A validated view over a ring region; split into the two
143	/// endpoint handles with [`Ring::split`].
144	///
145	/// - Geometry is snapshotted out of the header at
146	///   init/attach: per-op paths never re-read fields a peer
147	///   could scribble on, so a hostile peer can degrade the ring
148	///   to garbage messages or spurious Full/Empty, never to UB.
149	pub struct Ring<'a> {
150	    /// The region's control block.
151	    header: &'a Header,
152	    /// Base of the slot array (offset `size_of::<Header>()`).
153	    slots: *mut u8,
154	    /// Snapshot of `header.slot_size`.
155	    slot_size: u32,
156	    /// Snapshot of `header.capacity`.
157	    capacity: u32,
158	    /// Slot-position mask (`capacity - 1`).
159	    mask: u32,
160	    _region: PhantomData<&'a [u8]>,
161	}
162	
163	impl<'a> Ring<'a> {
164	    /// Initialize a fresh region and return the ring over it.
165	    ///
166	    /// - `slot_size` — N bytes per slot, a [`CACHE_LINE_SIZE`]
167	    ///   multiple.
168	    /// - `capacity` — M slots, a power of two `<= 2^31`.
169	    /// - The region must be [`CACHE_LINE_SIZE`]-aligned and at least
170	    ///   `size_of::<Header>() + M * N` bytes.
171	    pub fn init(region: &'a mut [u8], slot_size: u32, capacity: u32) -> Result<Self, Error> {
172	        validate_geometry(slot_size, capacity)?;
173	        let len = region.len();
174	        // Taken exactly once: a second `as_mut_ptr()` would
175	        // retag the slice and invalidate `header` under Stacked
176	        // Borrows (Miri-verified).
177	        let base = region.as_mut_ptr();
178	        let header = header_ptr(base, len)?;
179	        if (len as u64) < region_size(slot_size, capacity) {
180	            return Err(Error::TooSmall);
181	        }
182	        // SAFETY: alignment + room for the Header checked by
183	        // header_ptr; region is exclusively borrowed for 'a;
184	        // any byte pattern is a valid Header (all-atomic
185	        // fields, plain-byte padding).
186	        let header = unsafe { &*header };
187	        header
188	            .layout_version
189	            .store(LAYOUT_VERSION, Ordering::Relaxed);
190	        header.slot_size.store(slot_size, Ordering::Relaxed);
191	        header.capacity.store(capacity, Ordering::Relaxed);
192	        header
193	            .cache_line_size
194	            .store(CACHE_LINE_SIZE as u32, Ordering::Relaxed);
195	        header.producer_idx.store(0, Ordering::Relaxed);
196	        header.consumer_idx.store(0, Ordering::Relaxed);
197	        for word in header.user.iter() {
198	            word.store(0, Ordering::Relaxed);
199	        }
200	        // Published last: a peer that pre-mapped the region must
201	        // never observe MAGIC before the geometry it validates.
202	        // (Re-initializing a region a peer is already attached
203	        // to is outside the contract.)
204	        header.magic.store(MAGIC, Ordering::Release);
205	        // SAFETY: in bounds — region.len() >= header + slots.
206	        let slots = unsafe { base.add(size_of::<Header>()) };
207	        Ok(Ring {
208	            header,
209	            slots,
210	            slot_size,
211	            capacity,
212	            mask: capacity - 1,
213	            _region: PhantomData,
214	        })
215	    }
216	
217	    /// Attach to a region another process (or an earlier call)
218	    /// already initialized, validating its header.
219	    ///
220	    /// # Safety
221	    ///
222	    /// - `region` points to `len` bytes of memory that outlive
223	    ///   `'a`, genuinely shared and writable (e.g. a
224	    ///   `MAP_SHARED` mapping).
225	    /// - No other producer attaches if this side will produce;
226	    ///   likewise for the consumer side (SPSC contract).
227	    pub unsafe fn attach(region: *mut u8, len: usize) -> Result<Self, Error> {
228	        let header = header_ptr(region, len)?;
229	        // SAFETY: alignment + room for the Header checked by
230	        // header_ptr; caller guarantees the memory is live and
231	        // shared.
232	        let header = unsafe { &*header };
233	        // Acquire pairs with init's Release store of magic: a
234	        // valid magic means the geometry stores are visible.
235	        if header.magic.load(Ordering::Acquire) != MAGIC {
236	            return Err(Error::BadMagic);
237	        }
238	        if header.layout_version.load(Ordering::Relaxed) != LAYOUT_VERSION {
239	            return Err(Error::BadLayoutVersion);
240	        }
241	        if header.cache_line_size.load(Ordering::Relaxed) != CACHE_LINE_SIZE as u32 {
242	            return Err(Error::BadCacheLine);
243	        }
244	        // Snapshot geometry once; per-op paths never re-read it.
245	        let slot_size = header.slot_size.load(Ordering::Relaxed);
246	        let capacity = header.capacity.load(Ordering::Relaxed);
247	        validate_geometry(slot_size, capacity)?;
248	        if (len as u64) < region_size(slot_size, capacity) {
249	            return Err(Error::TooSmall);
250	        }
251	        // SAFETY: in bounds — len >= header + slots.
252	        let slots = unsafe { region.add(size_of::<Header>()) };
253	        Ok(Ring {
254	            header,
255	            slots,
256	            slot_size,
257	            capacity,
258	            mask: capacity - 1,
259	            _region: PhantomData,
260	        })
261	    }
262	
263	    /// Split into the producer and consumer endpoint handles.
264	    ///
265	    /// - Consuming `self` makes each handle exist at most once
266	    ///   per ring per process; cross-process, one producing and
267	    ///   one consuming process is the SPSC contract.
268	    pub fn split(self) -> (Producer<'a>, Consumer<'a>) {
269	        (
270	            Producer::new(
271	                self.header,
272	                self.slots,
273	                self.slot_size,
274	                self.capacity,
275	                self.mask,
276	            ),
277	            Consumer::new(self.header, self.slots, self.slot_size, self.mask),
278	        )
279	    }
280	}
281	
282	/// Validate a region base pointer and cast it to the `Header`
283	/// it must start with; shared by [`Ring::init`] / [`Ring::attach`].
284	///
285	/// - Checks alignment and room for the `Header` itself. The
286	///   full-geometry length check stays with the caller: init
287	///   knows the geometry from its parameters, attach only after
288	///   reading it from the returned header.
289	/// - Returns a raw pointer — no deref here. Each caller
290	///   discharges its own safety obligation (init: exclusive
291	///   borrow; attach: the caller's shared-mapping contract).
292	fn header_ptr(base: *mut u8, len: usize) -> Result<*const Header, Error> {
293	    if !(base as usize).is_multiple_of(CACHE_LINE_SIZE) {
294	        return Err(Error::Misaligned);
295	    }
296	    if len < size_of::<Header>() {
297	        return Err(Error::TooSmall);
298	    }
299	    Ok(base as *const Header)
300	}
301	
302	/// Bytes needed for a region with the given geometry.
303	///
304	/// - Computed in u64: the usize product can wrap on 32-bit
305	///   targets (e.g. N = 2^26, M = 2^6), which would validate a
306	///   tiny region and let safe code write out of bounds.
307	fn region_size(slot_size: u32, capacity: u32) -> u64 {
308	    size_of::<Header>() as u64 + slot_size as u64 * capacity as u64
309	}
310	
311	/// Shared geometry checks for [`Ring::init`] / [`Ring::attach`].
312	fn validate_geometry(slot_size: u32, capacity: u32) -> Result<(), Error> {
313	    if slot_size == 0 || !(slot_size as usize).is_multiple_of(CACHE_LINE_SIZE) {
314	        return Err(Error::BadSlotSize);
315	    }
316	    // The `> 1 << 31` arm is unreachable (u32 powers of two are
317	    // <= 2^31); it stays to document the M bound the occupancy
318	    // math relies on.
319	    if capacity == 0 || !capacity.is_power_of_two() || capacity > 1 << 31 {
320	        return Err(Error::BadCapacity);
321	    }
322	    Ok(())
323	}
324	
325	/// Check `T` fits a slot; called once per `reserve_slot_with`
326	/// (both endpoints).
327	///
328	/// - Panics on a type-geometry mismatch — that is a programming
329	///   error, not a runtime condition.
330	fn check_type<T>(slot_size: u32) {
331	    assert!(size_of::<T>() <= slot_size as usize, "T larger than slot");
332	    assert!(
333	        core::mem::align_of::<T>() <= CACHE_LINE_SIZE,
334	        "T alignment exceeds slot alignment"
335	    );
336	}
337	
338	/// Non-panicking form of [`check_type`], for descriptor
339	/// resolve — there the pool compared against is selected by
340	/// untrusted input, which must not be able to select a panic.
341	fn type_fits<T>(slot_size: u32) -> bool {
342	    size_of::<T>() <= slot_size as usize && core::mem::align_of::<T>() <= CACHE_LINE_SIZE
343	}
344	
345	/// Pointer to the slot for free-running index `idx`.
346	///
347	/// - Returned range is `slot_size` bytes, cache-line aligned
348	///   (base is, and slot_size is a line multiple).
349	fn slot_ptr(slots: *mut u8, idx: u32, mask: u32, slot_size: u32) -> *mut u8 {
350	    let pos = (idx & mask) as usize;
351	    // SAFETY: pos < capacity, so the offset is inside the slot
352	    // array validated at init/attach.
353	    unsafe { slots.add(pos * slot_size as usize) }
354	}
355	
356	#[cfg(test)]
357	mod tests {
358	    use super::*;
359	    use zerocopy::{FromBytes, Immutable, IntoBytes, KnownLayout};
360	
361	    /// Test message; two words so a torn write would be visible.
362	    #[derive(FromBytes, IntoBytes, KnownLayout, Immutable, Debug, PartialEq)]
363	    #[repr(C)]
364	    struct Msg {
365	        seq: u64,
366	        val: u64,
367	    }
368	
369	    /// Test region size: header + (4 slots × 1 line each).
370	    const REGION_BYTES: usize = size_of::<Header>() + (4 * CACHE_LINE_SIZE);
371	
372	    /// Cache-line-aligned backing store for the tests' rings.
373	    #[repr(C, align(64))]
374	    struct Region([u8; REGION_BYTES]);
375	
376	    impl Region {
377	        fn new() -> Self {
378	            Region([0; REGION_BYTES])
379	        }
380	    }
381	
382	    #[test]
383	    fn init_rejects_bad_geometry() {
384	        let mut r = Region::new();
385	        assert_eq!(
386	            Ring::init(&mut r.0, 63, 4).err().unwrap(),
387	            Error::BadSlotSize
388	        );
389	        assert_eq!(
390	            Ring::init(&mut r.0, 0, 4).err().unwrap(),
391	            Error::BadSlotSize
392	        );
393	        assert_eq!(
394	            Ring::init(&mut r.0, 64, 3).err().unwrap(),
395	            Error::BadCapacity
396	        );
397	        assert_eq!(
398	            Ring::init(&mut r.0, 64, 0).err().unwrap(),
399	            Error::BadCapacity
400	        );
401	        assert_eq!(Ring::init(&mut r.0, 64, 8).err().unwrap(), Error::TooSmall);
402	        assert_eq!(
403	            Ring::init(&mut r.0[1..], 64, 4).err().unwrap(),
404	            Error::Misaligned
405	        );
406	        // 32-bit tripwire: N * M wraps a 32-bit usize (2^26 *
407	        // 2^6 = 2^32); the u64 region_size must still reject it.
408	        assert_eq!(
409	            Ring::init(&mut r.0, 1 << 26, 1 << 6).err().unwrap(),
410	            Error::TooSmall
411	        );
412	    }
413	
414	    #[test]
415	    fn attach_validates_header() {
416	        let mut r = Region::new();
417	        // Not initialized yet: magic is zero.
418	        let err = unsafe { Ring::attach(r.0.as_mut_ptr(), r.0.len()) }
419	            .err()
420	            .unwrap();
421	        assert_eq!(err, Error::BadMagic);
422	        Ring::init(&mut r.0, 64, 4).unwrap();
423	        let ring = unsafe { Ring::attach(r.0.as_mut_ptr(), r.0.len()) }.unwrap();
424	        assert_eq!(ring.slot_size, 64);
425	        assert_eq!(ring.capacity, 4);
426	        assert_eq!(ring.mask, 3);
427	        // A region built with a different CACHE_LINE_SIZE (simulated
428	        // by editing the recorded value) is rejected.
429	        ring.header.cache_line_size.store(128, Ordering::Relaxed);
430	        let err = unsafe { Ring::attach(r.0.as_mut_ptr(), r.0.len()) }
431	            .err()
432	            .unwrap();
433	        assert_eq!(err, Error::BadCacheLine);
434	    }
435	
436	    #[test]
437	    fn user_words_zeroed_and_shared() {
438	        let mut r = Region::new();
439	        // Dirty the region so init's zeroing is observable.
440	        r.0.fill(0xAA);
441	        let ring = Ring::init(&mut r.0, 64, 4).unwrap();
442	        let (prod, mut cons) = ring.split();
443	        assert!(prod.user().iter().all(|w| w.load(Ordering::Relaxed) == 0));
444	        // Both endpoints see the same line; a producer-side
445	        // store is visible through the consumer's accessor.
446	        prod.user()[0].store(7, Ordering::Release);
447	        assert_eq!(cons.user()[0].load(Ordering::Acquire), 7);
448	        // The user line must not alias ring state: scribbling
449	        // all of it leaves the ring empty and functional.
450	        for w in cons.user().iter() {
451	            w.store(u32::MAX, Ordering::Relaxed);
452	        }
453	        assert!(cons.reserve_slot_with::<Msg>(|_| false).is_err());
454	    }
455	
456	    #[test]
457	    fn indices_survive_u32_wrap() {
458	        let mut r = Region::new();
459	        let ring = Ring::init(&mut r.0, 64, 4).unwrap();
460	        // Simulate a long-running ring two commits shy of the
461	        // u32 wrap (empty state: p == c).
462	        let start = u32::MAX - 1;
463	        ring.header.producer_idx.store(start, Ordering::Relaxed);
464	        ring.header.consumer_idx.store(start, Ordering::Relaxed);
465	        let (mut prod, mut cons) = ring.split();
466	
467	        // Fill: producer_idx runs MAX-1, MAX, 0, 1 — masked
468	        // slot positions 2, 3, 0, 1.
469	        for i in 0..4u64 {
470	            let mut slot = prod.reserve_slot_with::<Msg>(|_| false).unwrap();
471	            slot.seq = i;
472	            slot.val = i;
473	            slot.commit();
474	        }
475	        assert!(prod.reserve_slot_with::<Msg>(|_| false).is_err());
476	
477	        // Drain in order across the wrap.
478	        for i in 0..4u64 {
479	            let msg = cons.reserve_slot_with::<Msg>(|_| false).unwrap();
480	            assert_eq!(msg.seq, i);
481	            msg.release();
482	        }
483	        assert!(cons.reserve_slot_with::<Msg>(|_| false).is_err());
484	    }
485	
486	    #[test]
487	    fn roundtrip_full_empty() {
488	        let mut r = Region::new();
489	        let (mut prod, mut cons) = Ring::init(&mut r.0, 64, 4).unwrap().split();
490	
491	        // Empty at start.
492	        assert!(cons.reserve_slot_with::<Msg>(|_| false).is_err());
493	
494	        // Fill all 4 slots, then Full.
495	        for i in 0..4u64 {
496	            let mut slot = prod.reserve_slot_with::<Msg>(|_| false).unwrap();
497	            slot.seq = i;
498	            slot.val = i * 10;
499	            slot.commit();
500	        }
501	        assert!(prod.reserve_slot_with::<Msg>(|_| false).is_err());
502	
503	        // Drain in order; wrap: slot 0 is reused by seq 4.
504	        for i in 0..4u64 {
505	            let msg = cons.reserve_slot_with::<Msg>(|_| false).unwrap();
506	            assert_eq!(
507	                *msg,
508	                Msg {
509	                    seq: i,
510	                    val: i * 10
511	                }
512	            );
513	            msg.release();
514	        }
515	        assert!(cons.reserve_slot_with::<Msg>(|_| false).is_err());
516	
517	        // One more write lands in the masked-around slot 0.
518	        let mut slot = prod.reserve_slot_with::<Msg>(|_| false).unwrap();
519	        slot.seq = 4;
520	        slot.commit();
521	        let msg = cons.reserve_slot_with::<Msg>(|_| false).unwrap();
522	        assert_eq!(msg.seq, 4);
523	        msg.release();
524	    }
525	
526	    #[test]
527	    // Dropping the guards is the behavior under test; they have
528	    // no Drop impl by design (abandon = do nothing).
529	    #[allow(clippy::drop_non_drop)]
530	    fn abandoned_guards_publish_nothing() {
531	        let mut r = Region::new();
532	        let (mut prod, mut cons) = Ring::init(&mut r.0, 64, 4).unwrap().split();
533	
534	        // Reserve then drop: nothing published.
535	        let mut slot = prod.reserve_slot_with::<Msg>(|_| false).unwrap();
536	        slot.seq = 99;
537	        drop(slot);
538	        assert!(cons.reserve_slot_with::<Msg>(|_| false).is_err());
539	
540	        // Commit one, reserve then drop: still unread, the
541	        // next reservation returns it again.
542	        let mut slot = prod.reserve_slot_with::<Msg>(|_| false).unwrap();
543	        slot.seq = 1;
544	        slot.commit();
545	        let msg = cons.reserve_slot_with::<Msg>(|_| false).unwrap();
546	        assert_eq!(msg.seq, 1);
547	        drop(msg);
548	        let msg = cons.reserve_slot_with::<Msg>(|_| false).unwrap();
549	        assert_eq!(msg.seq, 1);
550	        msg.release();
551	    }
552	
553	    #[test]
554	    fn threaded_spsc() {
555	        // Reduced under Miri: interpreted spin loops are slow,
556	        // and its scheduler explores interleavings at any count.
557	        const COUNT: u64 = if cfg!(miri) { 200 } else { 100_000 };
558	        let mut r = Region::new();
559	        let (mut prod, mut cons) = Ring::init(&mut r.0, 64, 4).unwrap().split();
560	
561	        std::thread::scope(|s| {
562	            s.spawn(move || {
563	                for i in 0..COUNT {
564	                    loop {
565	                        match prod.reserve_slot_with::<Msg>(|_| false) {
566	                            Ok(mut slot) => {
567	                                slot.seq = i;
568	                                slot.val = i * 3;
569	                                slot.commit();
570	                                break;
571	                            }
572	                            Err(Full) => std::hint::spin_loop(),
573	                        }
574	                    }
575	                }
576	            });
577	            s.spawn(move || {
578	                for i in 0..COUNT {
579	                    loop {
580	                        match cons.reserve_slot_with::<Msg>(|_| false) {
581	                            Ok(msg) => {
582	                                assert_eq!(msg.seq, i);
583	                                assert_eq!(msg.val, i * 3);
584	                                msg.release();
585	                                break;
586	                            }
587	                            Err(Empty) => std::hint::spin_loop(),
588	                        }
589	                    }
590	                }
591	            });
592	        });
593	    }
594	
595	    #[test]
596	    fn reserve_slot_with_policy_counts_and_gives_up() {
597	        let mut r = Region::new();
598	        let (mut prod, mut cons) = Ring::init(&mut r.0, 64, 4).unwrap().split();
599	
600	        // Empty ring: the consumer's policy sees 0-based
601	        // attempts and its `false` becomes Err(Empty).
602	        let mut seen = Vec::new();
603	        let err = cons
604	            .reserve_slot_with::<Msg>(|attempt| {
605	                seen.push(attempt);
606	                attempt < 2
607	            })
608	            .err()
609	            .unwrap();
610	        assert_eq!(err, Empty);
611	        assert_eq!(seen, [0, 1, 2]);
612	
613	        // Fill the ring: the producer's policy gives up with
614	        // Err(Full).
615	        for i in 0..4 {
616	            let mut slot = prod.reserve_slot_with::<Msg>(|_| false).unwrap();
617	            slot.seq = i;
618	            slot.commit();
619	        }
620	        let err = prod
621	            .reserve_slot_with::<Msg>(|attempt| attempt < 2)
622	            .err()
623	            .unwrap();
624	        assert_eq!(err, Full);
625	
626	        // With room / messages available the policy is never
627	        // consulted.
628	        let msg = cons
629	            .reserve_slot_with::<Msg>(|_| panic!("policy consulted with a message available"))
630	            .unwrap();
631	        assert_eq!(msg.seq, 0);
632	        msg.release();
633	        let mut slot = prod
634	            .reserve_slot_with::<Msg>(|_| panic!("policy consulted with room available"))
635	            .unwrap();
636	        slot.seq = 4;
637	        slot.commit();
638	    }
639	
640	    #[test]
641	    fn threaded_spsc_spin_variants() {
642	        // The threaded_spsc flow through the shipped
643	        // policy::spin on both ends — the shipped-policy model
644	        // in use.
645	        const COUNT: u64 = if cfg!(miri) { 200 } else { 100_000 };
646	        let mut r = Region::new();
647	        let (mut prod, mut cons) = Ring::init(&mut r.0, 64, 4).unwrap().split();
648	
649	        std::thread::scope(|s| {
650	            s.spawn(move || {
651	                for i in 0..COUNT {
652	                    let mut slot = prod.reserve_slot_with::<Msg>(crate::policy::spin).unwrap();
653	                    slot.seq = i;
654	                    slot.val = i * 3;
655	                    slot.commit();
656	                }
657	            });
658	            s.spawn(move || {
659	                for i in 0..COUNT {
660	                    let msg = cons.reserve_slot_with::<Msg>(crate::policy::spin).unwrap();
661	                    assert_eq!(msg.seq, i);
662	                    assert_eq!(msg.val, i * 3);
663	                    msg.release();
664	                }
665	            });
666	        });
667	    }
668	}
