15	/// The consuming endpoint: `reserve_slot_with` the oldest
16	/// unread slot, read in place, `release`.
17	pub struct Consumer<'a> {
18	    /// The ring's control block.
19	    header: &'a Header,
20	    /// Base of the slot array.
21	    slots: *mut u8,
22	    /// Geometry snapshot (see [`Ring`](crate::Ring)).
23	    slot_size: u32,
24	    /// Slot-position mask (`capacity - 1`).
25	    mask: u32,
26	    _region: PhantomData<&'a [u8]>,
27	}
28	
29	// SAFETY: the handle owns the consumer role; see the Producer
30	// Send rationale.
31	unsafe impl Send for Consumer<'_> {}
32	
33	impl<'a> Consumer<'a> {
34	    /// Build the handle from [`Ring::split`](crate::Ring::split)'s
35	    /// geometry snapshot.
36	    pub(crate) fn new(header: &'a Header, slots: *mut u8, slot_size: u32, mask: u32) -> Self {
37	        Consumer {
38	            header,
39	            slots,
40	            slot_size,
41	            mask,
42	            _region: PhantomData,
43	        }
44	    }
45	
46	    /// The header's app-owned scratch line: zeroed at init,
47	    /// never touched by the crate again.
48	    ///
49	    /// - Shared with the peer: treat contents as untrusted
50	    ///   data — store values, never addresses to dereference.
51	    /// - See the design doc's "Blocking and user words" for
52	    ///   the wakeup-protocol contract it exists to host.
53	    pub fn user(&self) -> &[AtomicU32; USER_WORDS] {
54	        &self.header.user
55	    }
56	
