1	//! Demo binary: both primitives working across threads,
2	//! with throughput printed — run `cargo run --release`, or
3	//! `cargo install --path . --locked` and run
4	//! `zc-ring-x1-demo`. `-V`/`--version` prints the
5	//! version-of-record so you know exactly which build you
6	//! are testing.
7	//!
8	//! - Part 1, the ring: an SPSC pair moves typed messages
9	//!   in place (reserve → write → commit; reserve → read →
10	//!   release) — first both ends on one thread
11	//!   (the ring's own cost), then one producer thread to
12	//!   one consumer thread: unpinned, pinned to two different
13	//!   physical cores, and pinned to one physical core's two
14	//!   SMT siblings (shared L1/L2, when the CPU has SMT).
15	//! - Part 2, the pool: an allocator thread allocs and
16	//!   fills `BufSlot`s and hands them to a freer thread —
17	//!   "send" today is moving the guard (see the README's
18	//!   usage model); getting a buffer implies nothing about
19	//!   when it is sent or freed.
20	//! - The composed form — descriptors through the ring,
21	//!   payloads at rest in pool buffers — runs between them:
22	//!   alloc → into_desc → ring → resolve → free, with the
23	//!   same placement ladder as the raw ring.
24	
25	use std::time::Instant;
26	
27	use zc_ring_x1::{
28	    BufSlot, CACHE_LINE_SIZE, Desc, Empty, Exhausted, Full, Pool, PoolRegistry, Ring, policy,
29	};
30	use zerocopy::{FromBytes, Immutable, IntoBytes, KnownLayout};
31	
32	/// Messages moved per part.
33	const COUNT: u64 = 1_000_000;
34	
35	/// Ring slots / pool buffers (small on purpose: recycling
36	/// under pressure is the interesting case).
37	const DEPTH: u32 = 64;
38	
39	/// The demo message; one word carrying the sequence number
40	/// the consumer asserts.
41	#[derive(FromBytes, IntoBytes, KnownLayout, Immutable, Debug, PartialEq)]
42	#[repr(C)]
43	struct Msg {
44	    seq: u64,
45	}
46	
47	/// Region for either primitive: biggest header (ring, 4
48	/// lines) + DEPTH one-line slots/buffers.
49	#[repr(C, align(64))]
50	struct Region([u8; 4 * CACHE_LINE_SIZE + DEPTH as usize * CACHE_LINE_SIZE]);
51	
52	/// Group a count into comma-separated thousands
53	/// (`1234567` → `"1,234,567"`).
54	fn commas(n: u64) -> String {
55	    let digits = n.to_string();
56	    let mut out = String::with_capacity(digits.len() + digits.len() / 3);
57	    for (i, c) in digits.chars().enumerate() {
58	        if i > 0 && (digits.len() - i).is_multiple_of(3) {
59	            out.push(',');
60	        }
61	        out.push(c);
62	    }
63	    out
64	}
65	
66	/// Print one part's line: msgs/sec (comma-grouped) and
67	/// ns/msg from the part's elapsed seconds.
68	fn report(label: &str, secs: f64) {
69	    let rate = commas((COUNT as f64 / secs) as u64);
70	    let ns_per_msg = secs * 1e9 / COUNT as f64;
71	    println!("{label:<46} {rate:>12} msgs/sec  {ns_per_msg:>7.1} ns/msg");
72	}
73	
74	/// Parse a /sys cpu-list string ("0,12" or "0-2,6") into cpu
75	/// numbers; malformed pieces are skipped.
76	#[cfg(target_os = "linux")]
77	fn parse_cpu_list(s: &str) -> Vec<usize> {
78	    let mut out = Vec::new();
79	    for part in s.trim().split(',') {
80	        match part.split_once('-') {
81	            Some((lo, hi)) => {
82	                if let (Ok(lo), Ok(hi)) = (lo.parse::<usize>(), hi.parse::<usize>()) {
83	                    out.extend(lo..=hi);
84	                }
85	            }
86	            None => {
87	                if let Ok(n) = part.parse() {
88	                    out.push(n);
89	                }
90	            }
91	        }
92	    }
93	    out
94	}
95	
96	/// A `(producer cpu, consumer cpu)` pin for a 2t run;
97	/// `None` means the pair is unavailable / leave unpinned.
98	type PinPair = Option<(usize, usize)>;
99	
100	/// Discover two cpu pairs for the pinned 2t runs from
101	/// /sys/devices/system/cpu; `None` when the machine lacks the
102	/// shape (or not Linux).
103	///
104	/// - `.0` — same physical core: cpu0 and its SMT sibling
105	///   (shared L1/L2, the cheapest handoff).
106	/// - `.1` — different physical cores: cpu0 and a core outside
107	///   cpu0's L3 group when one exists (the farthest handoff),
108	///   else any non-sibling core.
109	#[cfg(target_os = "linux")]
110	fn discover_pin_pairs() -> (PinPair, PinPair) {
111	    let read = |path: &str| std::fs::read_to_string(path).ok();
112	    let siblings = read("/sys/devices/system/cpu/cpu0/topology/thread_siblings_list")
113	        .map(|s| parse_cpu_list(&s))
114	        .unwrap_or_default();
115	    let smt = (siblings.len() >= 2).then(|| (siblings[0], siblings[1]));
116	    let online = read("/sys/devices/system/cpu/online")
117	        .map(|s| parse_cpu_list(&s))
118	        .unwrap_or_default();
119	    let l3 = read("/sys/devices/system/cpu/cpu0/cache/index3/shared_cpu_list")
120	        .map(|s| parse_cpu_list(&s))
121	        .unwrap_or_else(|| siblings.clone());
122	    let far = online
123	        .iter()
124	        .copied()
125	        .find(|c| !l3.contains(c))
126	        .or_else(|| {
127	            online
128	                .iter()
129	                .copied()
130	                .find(|c| *c != 0 && !siblings.contains(c))
131	        });
132	    (smt, far.map(|c| (0, c)))
133	}
134	
135	/// Non-Linux stub: no pinned runs.
136	#[cfg(not(target_os = "linux"))]
137	fn discover_pin_pairs() -> (PinPair, PinPair) {
138	    (None, None)
139	}
140	
141	/// Pin the calling thread to `cpu` via sched_setaffinity;
142	/// panics on failure (a demo run with a silently ignored pin
143	/// would report a mislabeled number).
144	#[cfg(target_os = "linux")]
145	fn pin_to_cpu(cpu: usize) {
146	    // SAFETY: cpu_set_t is a plain bitmask; CPU_ZERO/CPU_SET
147	    // initialize it fully before sched_setaffinity reads it.
148	    unsafe {
149	        let mut set: libc::cpu_set_t = std::mem::zeroed();
150	        libc::CPU_ZERO(&mut set);
151	        libc::CPU_SET(cpu, &mut set);
152	        let rc = libc::sched_setaffinity(0, size_of::<libc::cpu_set_t>(), &set);
153	        assert_eq!(rc, 0, "sched_setaffinity({cpu}) failed");
154	    }
155	}
156	
157	/// Non-Linux stub: pinning is a no-op, so only the 1t runs
158	/// reach it (discover_pin_pairs returns no pairs); present
159	/// so the demo compiles everywhere.
160	#[cfg(not(target_os = "linux"))]
161	fn pin_to_cpu(_cpu: usize) {}
162	
163	/// Move COUNT messages single thread through the ring,
164	/// pinned to cpu 0 for consistency with the pinned 2t runs;
165	/// return elapsed seconds.
166	///
167	/// The loop runs in a scoped thread rather than pinning the
168	/// main thread: spawned threads inherit the main thread's
169	/// affinity mask, which would squeeze every later part onto
170	/// cpu 0.
171	fn spsc_ring_one_msg_1t() -> f64 {
172	    let mut region = Region([0; size_of::<Region>()]);
173	    let (mut producer, mut consumer) = Ring::init(&mut region.0, CACHE_LINE_SIZE as u32, DEPTH)
174	        .unwrap() // OK: Region is sized/aligned for the ring header + DEPTH slots
175	        .split();
176	
177	    let start = Instant::now();
178	    std::thread::scope(|s| {
179	        s.spawn(move || {
180	            pin_to_cpu(0);
181	            for i in 0..COUNT {
182	                match producer.reserve_slot_with::<Msg>(|_| false) {
183	                    Ok(mut slot) => {
184	                        slot.seq = i;
185	                        slot.commit();
186	                    }
187	                    Err(Full) => {
188	                        panic!("spsc_ring_one_msg_1t: producer Full SHOULD NOT HAPPEN");
189	                    }
190	                }
191	                match consumer.reserve_slot_with::<Msg>(|_| false) {
192	                    Ok(msg) => {
193	                        assert_eq!(msg.seq, i);
194	                        msg.release();
195	                    }
196	                    Err(Empty) => {
197	                        panic!("spsc_ring_one_msg_1t: consumer Empty SHOULD NOT HAPPEN");
198	                    }
199	                }
200	            }
201	        });
202	    });
203	    start.elapsed().as_secs_f64()
204	}
205	
206	/// Move COUNT messages producer-thread → consumer-thread
207	/// through the ring; return elapsed seconds.
208	///
209	/// - `pin` — `Some((p, c))` pins the producer to cpu `p` and
210	///   the consumer to cpu `c`; `None` lets the scheduler place
211	///   them (the number then depends on where they land).
212	fn spsc_ring_one_msg_2t(pin: PinPair) -> f64 {
213	    let mut region = Region([0; size_of::<Region>()]);
214	    let (mut producer, mut consumer) = Ring::init(&mut region.0, CACHE_LINE_SIZE as u32, DEPTH)
215	        .unwrap() // OK: Region is sized/aligned for the ring header + DEPTH slots
216	        .split();
217	
218	    let start = Instant::now();
219	    std::thread::scope(|s| {
220	        s.spawn(move || {
221	            if let Some((p, _)) = pin {
222	                pin_to_cpu(p);
223	            }
224	            for i in 0..COUNT {
225	                let mut slot = producer.reserve_slot_with::<Msg>(policy::spin).unwrap(); // OK: policy::spin never gives up
226	                slot.seq = i;
227	                slot.commit();
228	            }
229	        });
230	        s.spawn(move || {
231	            if let Some((_, c)) = pin {
232	                pin_to_cpu(c);
233	            }
234	            for i in 0..COUNT {
235	                let msg = consumer.reserve_slot_with::<Msg>(policy::spin).unwrap(); // OK: policy::spin never gives up
236	                assert_eq!(msg.seq, i);
237	                msg.release();
238	            }
239	        });
240	    });
241	    start.elapsed().as_secs_f64()
242	}
243	
244	/// The composed flow on one thread pinned to cpu 0: one pool
245	/// message allocated outside the timed loop; each iteration
246	/// populates it, converts guard → descriptor, rings the
247	/// descriptor across, and resolves the guard back; return
248	/// elapsed seconds.
249	///
250	/// - Isolates messaging cost (into_desc + ring + resolve)
251	///   from the pool cycle — pool_alloc_free_1t reports that
252	///   separately.
253	/// - The guard and the descriptor are the two exclusive
254	///   forms of ownership, so the per-iteration conversion
255	///   cannot hoist: converting *is* the send-side handoff.
256	///   The 2t variant keeps alloc/free per message because
257	///   there ownership genuinely leaves the producer.
258	fn spsc_ring_one_pool_msg_1t() -> f64 {
259	    let mut ring_region = Region([0; size_of::<Region>()]);
260	    let mut pool_region = Region([0; size_of::<Region>()]);
261	    let mut pool = Pool::init(&mut pool_region.0, CACHE_LINE_SIZE as u32, DEPTH).unwrap(); // OK: Region is sized/aligned for the pool header + DEPTH buffers
262	    let mut registry = PoolRegistry::<1>::new();
263	    let pool_id = registry.register(pool.resolver()).unwrap(); // OK: empty capacity-1 registry always has room
264	    let (mut producer, mut consumer) =
265	        Ring::init(&mut ring_region.0, CACHE_LINE_SIZE as u32, DEPTH)
266	            .unwrap() // OK: Region is sized/aligned for the ring header + DEPTH slots
267	            .split();
268	
269	    let start = Instant::now();
270	    std::thread::scope(|s| {
271	        s.spawn(move || {
272	            pin_to_cpu(0);
273	            let mut buf_slot = pool.alloc::<Msg>().unwrap(); // OK: fresh pool, DEPTH buffers free
274	            for i in 0..COUNT {
275	                buf_slot.seq = i;
276	                let desc = registry
277	                    .into_desc(pool_id, buf_slot)
278	                    .map_err(|(_, e)| e)
279	                    .unwrap(); // OK: pool_id came from this registry's register
280	                match producer.reserve_slot_with::<Desc>(|_| false) {
281	                    Ok(mut slot) => {
282	                        *slot = desc;
283	                        slot.commit();
284	                    }
285	                    Err(Full) => {
286	                        panic!("spsc_ring_one_pool_msg_1t: producer Full SHOULD NOT HAPPEN");
287	                    }
288	                }
289	                buf_slot = match consumer.reserve_slot_with::<Desc>(|_| false) {
290	                    Ok(slot) => {
291	                        let desc = *slot;
292	                        slot.release();
293	                        // SAFETY: the desc was consumed into
294	                        // the ring by into_desc above and is
295	                        // resolved exactly once, same thread.
296	                        let msg = unsafe { registry.resolve::<Msg>(desc) }.unwrap(); // OK: desc came from into_desc on this pool
297	                        assert_eq!(msg.seq, i);
298	                        msg
299	                    }
300	                    Err(Empty) => {
301	                        panic!("spsc_ring_one_pool_msg_1t: consumer Empty SHOULD NOT HAPPEN");
302	                    }
303	                };
304	            }
305	            buf_slot.free();
306	        });
307	    });
308	    start.elapsed().as_secs_f64()
309	}
310	
311	/// The composed flow producer-thread → consumer-thread:
312	/// alloc + fill pool messages on the producer, descriptors
313	/// cross the SPSC ring, the consumer resolves and frees;
314	/// return elapsed seconds.
315	///
316	/// - `pin` — `Some((p, c))` pins the producer to cpu `p` and
317	///   the consumer to cpu `c`; `None` lets the scheduler place
318	///   them (the number then depends on where they land).
319	fn spsc_ring_one_pool_msg_2t(pin: PinPair) -> f64 {
320	    let mut ring_region = Region([0; size_of::<Region>()]);
321	    let mut pool_region = Region([0; size_of::<Region>()]);
322	    let mut pool = Pool::init(&mut pool_region.0, CACHE_LINE_SIZE as u32, DEPTH).unwrap(); // OK: Region is sized/aligned for the pool header + DEPTH buffers
323	    let mut registry = PoolRegistry::<1>::new();
324	    let pool_id = registry.register(pool.resolver()).unwrap(); // OK: empty capacity-1 registry always has room
325	    let registry = &registry;
326	    let (mut producer, mut consumer) =
327	        Ring::init(&mut ring_region.0, CACHE_LINE_SIZE as u32, DEPTH)
328	            .unwrap() // OK: Region is sized/aligned for the ring header + DEPTH slots
329	            .split();
330	
331	    let start = Instant::now();
332	    std::thread::scope(|s| {
333	        s.spawn(move || {
334	            if let Some((p, _)) = pin {
335	                pin_to_cpu(p);
336	            }
337	            for i in 0..COUNT {
338	                let mut buf_slot = loop {
339	                    match pool.alloc::<Msg>() {
340	                        Ok(buf_slot) => break buf_slot,
341	                        Err(Exhausted) => std::hint::spin_loop(),
342	                    }
343	                };
344	                buf_slot.seq = i;
345	                let desc = registry
346	                    .into_desc(pool_id, buf_slot)
347	                    .map_err(|(_, e)| e)
348	                    .unwrap(); // OK: pool_id came from this registry's register
349	                let mut slot = producer.reserve_slot_with::<Desc>(policy::spin).unwrap(); // OK: policy::spin never gives up
350	                *slot = desc;
351	                slot.commit();
352	            }
353	        });
354	        s.spawn(move || {
355	            if let Some((_, c)) = pin {
356	                pin_to_cpu(c);
357	            }
358	            for i in 0..COUNT {
359	                let desc = {
360	                    let slot = consumer.reserve_slot_with::<Desc>(policy::spin).unwrap(); // OK: policy::spin never gives up
361	                    let desc = *slot;
362	                    slot.release();
363	                    desc
364	                };
365	                // SAFETY: the desc was consumed into the ring
366	                // by the producer and read after the commit →
367	                // reserve handoff (happens-before); each is
368	                // resolved exactly once.
369	                let msg = unsafe { registry.resolve::<Msg>(desc) }.unwrap(); // OK: descs here only come from the producer's into_desc
370	                assert_eq!(msg.seq, i);
371	                msg.free();
372	            }
373	        });
374	    });
375	    start.elapsed().as_secs_f64()
376	}
377	
378	/// Alloc + fill COUNT messages on an allocator thread,
379	/// free them on a freer thread (guards cross a std
380	/// channel); return elapsed seconds.
381	///
382	/// - `pin` — `Some((a, f))` pins the allocator to cpu `a`
383	///   and the freer to cpu `f`; `None` lets the scheduler
384	///   place them (the number then depends on where they
385	///   land).
386	fn std_mpsc_one_pool_msg_2t(pin: PinPair) -> f64 {
387	    let mut region = Region([0; size_of::<Region>()]);
388	    let mut pool = Pool::init(&mut region.0, CACHE_LINE_SIZE as u32, DEPTH).unwrap(); // OK: Region is sized/aligned for the pool header + DEPTH buffers
389	
390	    let (tx, rx) = std::sync::mpsc::sync_channel::<BufSlot<'_, Msg>>(DEPTH as usize);
391	    let start = Instant::now();
392	    std::thread::scope(|s| {
393	        s.spawn(move || {
394	            if let Some((a, _)) = pin {
395	                pin_to_cpu(a);
396	            }
397	            for i in 0..COUNT {
398	                loop {
399	                    match pool.alloc::<Msg>() {
400	                        Ok(mut buf_slot) => {
401	                            buf_slot.seq = i;
402	                            tx.send(buf_slot).unwrap();
403	                            break;
404	                        }
405	                        Err(Exhausted) => std::hint::spin_loop(),
406	                    }
407	                }
408	            }
409	        });
410	        s.spawn(move || {
411	            if let Some((_, f)) = pin {
412	                pin_to_cpu(f);
413	            }
414	            for i in 0..COUNT {
415	                let buf_slot = rx.recv().unwrap();
416	                assert_eq!(buf_slot.seq, i);
417	                buf_slot.free();
418	            }
419	        });
420	    });
421	    start.elapsed().as_secs_f64()
422	}
423	
424	/// The std-channel flow on one thread pinned to cpu 0: alloc
425	/// a pool message, move its guard through a sync_channel,
426	/// receive and free it; return elapsed seconds.
427	fn std_mpsc_one_pool_msg_1t() -> f64 {
428	    let mut region = Region([0; size_of::<Region>()]);
429	    let mut pool = Pool::init(&mut region.0, CACHE_LINE_SIZE as u32, DEPTH).unwrap(); // OK: Region is sized/aligned for the pool header + DEPTH buffers
430	    let (tx, rx) = std::sync::mpsc::sync_channel::<BufSlot<'_, Msg>>(DEPTH as usize);
431	
432	    let start = Instant::now();
433	    std::thread::scope(|s| {
434	        s.spawn(move || {
435	            pin_to_cpu(0);
436	            for i in 0..COUNT {
437	                let mut buf_slot = pool.alloc::<Msg>().unwrap(); // OK: alloc+free per iteration, DEPTH never exceeded
438	                buf_slot.seq = i;
439	                tx.send(buf_slot).unwrap(); // OK: capacity DEPTH, at most one in flight
440	                let buf_slot = rx.recv().unwrap(); // OK: just sent on this thread
441	                assert_eq!(buf_slot.seq, i);
442	                buf_slot.free();
443	            }
444	        });
445	    });
446	    start.elapsed().as_secs_f64()
447	}
448	
449	/// Alloc → write → free COUNT messages on one thread pinned
450	/// to cpu 0 — the pool's own cost, no channel, no second
451	/// thread; return elapsed seconds.
452	///
453	/// Runs in a scoped thread like the other pinned parts, so
454	/// the main thread's affinity stays untouched.
455	fn pool_alloc_free_1t() -> f64 {
456	    let mut region = Region([0; size_of::<Region>()]);
457	    let mut pool = Pool::init(&mut region.0, CACHE_LINE_SIZE as u32, DEPTH).unwrap(); // OK: Region is sized/aligned for the pool header + DEPTH buffers
458	
459	    let start = Instant::now();
460	    std::thread::scope(|s| {
461	        s.spawn(move || {
462	            pin_to_cpu(0);
463	            for i in 0..COUNT {
464	                let mut buf_slot = pool.alloc::<Msg>().unwrap(); // OK: alloc+free per iteration, DEPTH never exceeded
465	                buf_slot.seq = i;
466	                std::hint::black_box(buf_slot.seq);
467	                buf_slot.free();
468	            }
469	        });
470	    });
471	    start.elapsed().as_secs_f64()
472	}
473	
474	/// The same loop through the global allocator (Box::new →
475	/// write → drop) for comparison, pinned to cpu 0; return
476	/// elapsed seconds.
477	///
478	/// Runs in a scoped thread like the other pinned parts, so
479	/// the main thread's affinity stays untouched.
480	fn global_alloc_free_1t() -> f64 {
481	    let start = Instant::now();
482	    std::thread::scope(|s| {
483	        s.spawn(move || {
484	            pin_to_cpu(0);
485	            for i in 0..COUNT {
486	                let mut buf = std::hint::black_box(Box::new(Msg { seq: 0 }));
487	                buf.seq = i;
488	                std::hint::black_box(buf.seq);
489	                drop(buf);
490	            }
491	        });
492	    });
493	    start.elapsed().as_secs_f64()
494	}
495	
496	/// Run both parts and print their throughput; `-V` /
497	/// `--version` prints the version-of-record and exits.
498	fn main() {
499	    let banner = concat!(env!("CARGO_PKG_NAME"), " ", env!("CARGO_PKG_VERSION"));
500	    println!("{banner}");
501	    if std::env::args().any(|a| a == "-V" || a == "--version") {
502	        return;
503	    }
504	    println!("demo: {} messages each, depth {DEPTH}", commas(COUNT));
505	    let (smt, far) = discover_pin_pairs();
506	
507	    // Alloc/free baselines, then message flows — like
508	    // compares with like within each block.
509	    report("pool_alloc_free_1t (core 0):", pool_alloc_free_1t());
510	    report("global_alloc_free_1t (core 0):", global_alloc_free_1t());
511	
512	    // Single thread, core 0.
513	    println!();
514	    report("spsc_ring_one_msg_1t (core 0):", spsc_ring_one_msg_1t());
515	    report(
516	        "spsc_ring_one_pool_msg_1t (core 0):",
517	        spsc_ring_one_pool_msg_1t(),
518	    );
519	    report(
520	        "std_mpsc_one_pool_msg_1t (core 0):",
521	        std_mpsc_one_pool_msg_1t(),
522	    );
523	
524	    // Two threads, scheduler-placed.
525	    println!();
526	    report(
527	        "spsc_ring_one_msg_2t (unpinned):",
528	        spsc_ring_one_msg_2t(None),
529	    );
530	    report(
531	        "spsc_ring_one_pool_msg_2t (unpinned):",
532	        spsc_ring_one_pool_msg_2t(None),
533	    );
534	    report(
535	        "std_mpsc_one_pool_msg_2t (unpinned):",
536	        std_mpsc_one_pool_msg_2t(None),
537	    );
538	
539	    // Two threads, different physical cores.
540	    println!();
541	    match far {
542	        Some((p, c)) => {
543	            report(
544	                &format!("spsc_ring_one_msg_2t (diff cores {p}+{c}):"),
545	                spsc_ring_one_msg_2t(far),
546	            );
547	            report(
548	                &format!("spsc_ring_one_pool_msg_2t (diff cores {p}+{c}):"),
549	                spsc_ring_one_pool_msg_2t(far),
550	            );
551	            report(
552	                &format!("std_mpsc_one_pool_msg_2t (diff cores {p}+{c}):"),
553	                std_mpsc_one_pool_msg_2t(far),
554	            );
555	        }
556	        None => {
557	            println!("2t diff-cores runs:");
558	            println!("  skipped, only one core found");
559	        }
560	    }
561	
562	    // Two threads, one physical core (SMT siblings).
563	    println!();
564	    match smt {
565	        Some((p, c)) => {
566	            report(
567	                &format!("spsc_ring_one_msg_2t (same core {p}+{c}):"),
568	                spsc_ring_one_msg_2t(smt),
569	            );
570	            report(
571	                &format!("spsc_ring_one_pool_msg_2t (same core {p}+{c}):"),
572	                spsc_ring_one_pool_msg_2t(smt),
573	            );
574	            report(
575	                &format!("std_mpsc_one_pool_msg_2t (same core {p}+{c}):"),
576	                std_mpsc_one_pool_msg_2t(smt),
577	            );
578	        }
579	        None => {
580	            println!("2t same-core runs:");
581	            println!("  skipped, no SMT sibling found");
582	        }
583	    }
584	}
